import{_ as o,o as s,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"20. Roster Design Safe Hours Of Work","description":"","frontmatter":{"title":"20. Roster Design Safe Hours Of Work","eba":"Medical Specialists 2022-2026","topics":["hours","rosters","staffing","workload"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/20-roster-design-safe-hours-of-work.md","filePath":"ebas/medical-specialists/employment/20-roster-design-safe-hours-of-work.md"}'),a={name:"ebas/medical-specialists/employment/20-roster-design-safe-hours-of-work.md"};function i(n,e,f,l,c,d){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_20-roster-design-safe-hours-of-work" tabindex="-1">20. Roster Design Safe Hours Of Work <a class="header-anchor" href="#_20-roster-design-safe-hours-of-work" aria-label="Permalink to &quot;20. Roster Design Safe Hours Of Work&quot;">​</a></h1><p><strong>20.1</strong> The provisions of this clause are to be read in conjunction with <a href="/eba/ebas/medical-specialists/employment/21-workload-management-and-review.html">clause 21</a> (Workload Management).</p><p><strong>20.2</strong> The Health Service must not roster or arrange work hours in a way that causes an excessive or unsafe work pattern to exist.</p><p><strong>20.3</strong> The obligation to work safe hours applies to both the Health Service and Doctors.</p><p><strong>20.4</strong> While not binding on the Health Services, the National Code of Practice – Hours of Work, Shiftwork and Rostering for Hospital Doctors recommends minimum periods of rest between different forms of rostered work (e.g. 10 hours between successive ordinary rostered shifts), and is a suitable framework under which to consider safe working hours issues.</p><p>Plain language terms: ordinary hours.</p>',6)])])}const u=o(a,[["render",i]]);export{p as __pageData,u as default};
